let currentChatLang = 'en';
const diseaseTranslationCache = new Map();

async function translateDiseaseText(text){
  if(currentChatLang === 'en' || !text) return text;
  const cacheKey = currentChatLang + '|' + text;
  if(diseaseTranslationCache.has(cacheKey)) return diseaseTranslationCache.get(cacheKey);

  const target = currentChatLang;
  const attempts = [
    async () => {
      const url = 'https://api.mymemory.translated.net/get?q=' + encodeURIComponent(text) + '&langpair=en|' + target;
      const res = await fetch(url);
      const data = await res.json();
      return data && data.responseData && data.responseData.translatedText ? data.responseData.translatedText : null;
    },
    async () => {
      const res = await fetch('https://translate.argosopentech.com/translate',{
        method:'POST',
        headers:{'Content-Type':'application/json'},
        body:JSON.stringify({q:text, source:'en', target:target, format:'text'})
      });
      const data = await res.json();
      return data && data.translatedText ? data.translatedText : null;
    }
  ];

  for(const attempt of attempts){
    try{
      const translated = await attempt();
      if(translated && translated.trim()){
        diseaseTranslationCache.set(cacheKey, translated);
        return translated;
      }
    }catch(err){
      console.warn('Disease translation failed:', err);
    }
  }
  return text;
}

async function translateDiseaseObject(info){
  if(currentChatLang === 'en') return info;
  return {
    description: await translateDiseaseText(info.description),
    symptoms: await translateDiseaseText(info.symptoms),
    management: await translateDiseaseText(info.management),
    precautions: await translateDiseaseText(info.precautions)
  };
}

function normalizeDiseaseInput(input){
  return (input||'').toLowerCase().replace(/[^a-z0-9]/g,'');
}

function levenshteinDistance(a,b){
  a=normalizeDiseaseInput(a); b=normalizeDiseaseInput(b);
  const dp=Array.from({length:b.length+1},()=>Array(a.length+1).fill(0));
  for(let i=0;i<=b.length;i++) dp[i][0]=i;
  for(let j=0;j<=a.length;j++) dp[0][j]=j;
  for(let i=1;i<=b.length;i++){
    for(let j=1;j<=a.length;j++){
      const cost = b[i-1]===a[j-1] ? 0 : 1;
      dp[i][j]=Math.min(dp[i-1][j]+1, dp[i][j-1]+1, dp[i-1][j-1]+cost);
    }
  }
  return dp[b.length][a.length];
}

function suggestDiseaseName(input){
  const q=normalizeDiseaseInput(input);
  if(!q) return null;
  let best=null, bestDist=Infinity;
  for(const key of Object.keys(diseaseDB)){
    const dist = levenshteinDistance(q, key);
    if(dist < bestDist){
      bestDist = dist;
      best = key;
    }
  }
  return bestDist <= Math.max(2, Math.floor(q.length*0.25)) ? best : null;
}

async function fetchDiseaseFallbackFromWiki(rawName){
  try{
    const safe = encodeURIComponent((rawName||'').trim());
    const res = await fetch('https://en.wikipedia.org/api/rest_v1/page/summary/' + safe);
    if(!res.ok) return null;
    const data = await res.json();
    if(!data || !data.extract) return null;
    return {
      description: data.extract,
      symptoms: 'Detailed symptoms may vary. Please verify with a qualified healthcare professional.',
      management: 'Consult a doctor for confirmation, diagnosis, and treatment planning.',
      precautions: 'Do not self-diagnose serious symptoms. Seek medical care if symptoms worsen or are urgent.'
    };
  }catch(err){
    console.warn('Wikipedia fallback failed:', err);
    return null;
  }
}


