  // Download Report
  const dlBtn=document.getElementById('download-report-btn');
  if(dlBtn) dlBtn.addEventListener('click',generateAndDownloadReport);

  function getChatHistory(){
    const msgs=[];
    document.querySelectorAll('#chat-messages .message').forEach(m=>{
      const isUser=m.classList.contains('user-message');
      const bubble=m.querySelector('.msg-bubble');
      const time=m.querySelector('.msg-time');
      if(bubble){
        // Strip inner HTML tags for plain text but keep structure
        const clone=bubble.cloneNode(true);
        // Remove typing dots
        const dots=clone.querySelector('.typing-dots');
        if(dots) dots.remove();
        msgs.push({role:isUser?'Patient':'BLUEWAVE AI',html:clone.innerHTML,time:time?time.textContent:''});
      }
    });
    return msgs;
  }

  function getRelevantPrecautions(){
    if(!userProfile.conditions||userProfile.conditions==='None specified') return [];
    const cond=(userProfile.conditions||'').toLowerCase();
    const found=[];
    for(const [key,info] of Object.entries(diseaseDB)){
      if(cond.includes(key.toLowerCase())){
        found.push({name:key.charAt(0).toUpperCase()+key.slice(1),precautions:info.precautions,symptoms:info.symptoms,management:info.management});
      }
    }
    return found;
  }

